property.embedded_functions:

#include <stdio.h>
int registrationRequests[MAX_UES] = {0};
uint64_t lastRegistrationTime[MAX_UES] = {0};

void updateRegistration Counters(uint64_t timestamp, uint32_t amfUeId) {
  if (amfUeId >= MAX_UES) return;
  registrationRequests[amfUeId]++;
  lastRegistrationTime[amfUeId] = timestamp;
}

int isSurgeDetected(uint64_t currentTime, uint32_t amfUeId, uint32_t threshold, uint64_t windowSize) {
  if (registrationRequests[amfUeId] > threshold && (currentTime - lastRegistrationTime[amfUeId]) < windowSize) {
    return 1;
  }
  return 0;
}

void on_load() {}
void on_unload() {}
